powerpagecomponent.content:
{
  "source": "<!-- Last modified Tue Oct 21 12:39PM -->
<!-- Last modified Sat Aug 30 10:04AM -->

<!-- ENTER fxmLoanOfficerAssignment ~assign -->

{% fetchxml fxmLoanOfficer %}
	<fetch>
		<entity name="lv_lvcomploanofficer">
			<attribute name="lv_lvcomploanofficerid" />
			<attribute name="lv_name" />
			<order attribute="lv_name" />
		</entity>
	</fetch>
{% endfetchxml %}

{% fetchxml fxmRegionBranch %}
	<fetch>
		<entity name="lv_lvcompregionbranch">
			<attribute name="lv_region" />
			<attribute name="lv_branch" />
		</entity>
	</fetch>
{% endfetchxml %}

{% fetchxml fxmRBLO %}
	<fetch>
		<entity name="lv_lvcompregionbranchloanofficer">
			<attribute name="lv_region" />
			<attribute name="lv_branch" />
			<attribute name="lv_loanofficer" />
		</entity>
	</fetch>
{% endfetchxml %}

{% assign tblRegionBranch = fxmRegionBranch.results.entities %}
{% assign tblRBLO = fxmRBLO.results.entities %}
{% assign tblLoanOfficer = fxmLoanOfficer.results.entities %}

<div class="page-container">

    <!-- Individual Loan Officer Section - Collapsible -->
    <div class="collapsible-section">

		<div class="section-header" onclick="toggleSection('individualOfficerSection')" title="Select a single loan officer, then add or remove assignments">
			<div class="header-content">
				<h2>By Individual Loan Officer</h2>
				<p class="section-subheader">View or set region and branch assignments for a single officer</p>
			</div>
			<div class="toggle-icon">▶</div>
		</div>

        <div id="individualOfficerSection" class="section-content" style="display: none;">
            <div class="form-container officer-lookup-container">
                <div class="form-group">
                    <label for="officerLookup">Loan Officer</label>
                    <select id="officerLookup" onchange="handleOfficerLookup()" class="rj-persist">
                        <option value="">Select a loan officer</option>
                        {% for officer in tblLoanOfficer %}
                            <option value="{{officer.lv_lvcomploanofficerid}}">{{officer.lv_name}}</option>
                        {% endfor %}
                    </select>
                </div>
            </div>

            <div id="officerAssignmentsContainer" style="display: none;">
                <h3>Current Assignments <span id="officerAssignmentCount"></span>
                    <span id="officerSaveChangesContainer" style="margin-left: 15px; min-width: 120px; display: inline-block;">
                        <a id="officerSaveChangesLink" href="#" class="save-changes-link" style="display: none;"></a>
                    </span>
                </h3>

                <div id="officerAssignmentsList"></div> {% comment %}  This div gets populated in javascript {% endcomment %} 

                <div class="add-assignment-container">
                    <div class="add-assignment-header">
                        <a href="#" id="addAssignmentLink" class="add-link">+ Add</a>
                    </div>
                    <div id="addAssignmentControls" style="display: none;" class="add-assignment-controls">
                        <div class="form-group">
							<select id="officerRegionSelect" onchange="handleOfficerRegionChange()" class="rj-persist">
								<option value="">Select a region</option>
								{% for region in regionQuery.results.entities %}
									<option value="{{region.name}}">{{region.name}}</option>
								{% endfor %}
							</select>
						</div>

                        <div class="form-group">
                            <select id="officerBranchSelect"  class="rj-persist" disabled>
                                <option value="">Select a branch</option>
                            </select>
                        </div>
                        <div class="form-group">
                            <button id="confirmAddAssignment" class="btn-add" disabled>Add</button>
                        </div>
                    </div>
                </div>
            </div>
        </div>
    </div>

    <!-- Region/Branch Section - Collapsible -->
    <div class="collapsible-section">

		<div class="section-header" onclick="toggleSection('regionBranchSection')"  title="Select a Region and Branch combination and see assignments for all loan officers">
			<div class="header-content">
				<h2>By Region and Branch, All Officers</h2>
				<p class="section-subheader">For selected Region and Branch, show all loan officer assignments</p>
			</div>
			<div class="toggle-icon">▶</div>
		</div>

        <div id="regionBranchSection" class="section-content" style="display: none;">                                {% comment %}  Region, Branch, and Filter Dropdowns  {% endcomment %} 
            <div id="fc1" class="form-container">
                <div class="form-group">
                    <label for="regionSelect">Region</label>                                                         {% comment %}  REGION DROPDOWN  {% endcomment %} 
					<select id="regionSelect" onchange="handleRegionChange()" class="rj-persist">
						<option value="">Select a region</option>
						{% for region in regionQuery.results.entities %}
							<option value="{{region.name}}">{{region.name}}</option>
						{% endfor %}
					</select>
				</div>

                <div class="form-group">                                                                             {% comment %}  BRANCH DROPDOWN - populated in javascript  {% endcomment %} 
                    <label for="branchSelect">Branch</label>
                    <select id="branchSelect" onchange="handleBranchChange()" class="rj-persist" disabled>
                        <option value="">Select a branch</option>
                    </select>
                </div>

                <div class="form-group">                                                                             {% comment %}  FILTER DROPDOWN  {% endcomment %} 
                    <label for="filterSelect">Show</label>
                    <select id="filterSelect" style="min-width: 260px" onchange="handleFilterChange()"  class="rj-persist" disabled>
                        <option value="all">All Loan Officers</option>
                        <option value="assigned">Assigned Loan Officers Only</option>
                        <option value="unassigned">Unassigned Loan Officers Only</option>
                    </select>
                </div>
            </div>

            <div id="loanOfficersContainer" style="display: none;">
                <h3>Loan Officers <span id="saveChangesContainer" style="margin-left: 15px; min-width: 120px; display: inline-block;">
                    <a id="saveChangesLink" href="#" class="save-changes-link" style="display: none;"></a>
                </span></h3>
                <div id="loanOfficersList"></div>
            </div>
        </div>
    </div>
</div>

<script>
// Initialize all the data from Liquid templates
const branches = [
    {% for branch in tblRegionBranch %}
        {
			regionId: "{{branch.lv_region.id}}",
			regionName: "{{branch.lv_region.name}}",
			branchId: "{{branch.lv_branch.id}}",
			branchName: "{{branch.lv_branch.name}}"
        },
    {% endfor %}
];

const loanOfficers = [
    {% for officer in tblLoanOfficer %}
        {
            id: "{{officer.lv_lvcomploanofficerid}}",
            name: "{{officer.lv_name}}"
        },
    {% endfor %}
];

const assignments = [
    {% for row in tblRBLO %}
        {
			id:  "{{row.lv_lvcompregionbranchloanofficerid}}",
            regionName: "{{row.lv_region.name}}",
            branchName: "{{row.lv_branch.name}}",
            officerId: "{{row.lv_loanofficer.id}}"
        },
    {% endfor %}
];

// No, do not do this here, is in global
// let CS_RF_TO_KEN = '';

let currentFilter = 'all';

let currentSortColumn = 'name'; // Default sort column
let currentSortDirection = 'asc'; // Default sort direction
let changes = []; // Unsaved changes
let officerChanges = []; // Unsaved changes for individual officer

function toggleSection(sectionId) {
    const content = document.getElementById(sectionId);
    const header = content.previousElementSibling;
    const icon = header.querySelector('.toggle-icon');

    if (content.style.display === "none") {
        content.style.display = "block";
        //icon.textContent = "▼"; // Down arrow when expanded
		icon.textContent = "◀"; 
    } else {
        content.style.display = "none";
        icon.textContent = "▶"; // Right arrow when collapsed
    }
}

// #region Loan Officer

function handleOfficerLookup() {
	const officerSelect = $('#officerLookup');
	const selectedOfficerId = officerSelect.val();

	const container = $('#officerAssignmentsContainer');
	const list = $('#officerAssignmentsList');
	const countSpan = $('#officerAssignmentCount');

	// Clear the list
	list.empty();

	if (!selectedOfficerId) {
		container.hide();
		$('#addAssignmentControls').hide();
		return;
	}

	// Find the selected officer's name
	const selectedOfficer = loanOfficers.find(o => o.id === selectedOfficerId);

	// Get all assignments for this officer
	const officerAssignments = assignments.filter(a => a.officerId === selectedOfficerId);

	// Update assignment count
	countSpan.text(`(${officerAssignments.length})`);

	if (officerAssignments.length === 0) {
		list.html('<p>This loan officer has no current assignments.</p>');
	} else {
		// Create a table for the assignments
		const table = $('<table>').addClass('loan-officers-table');

		// Add table header
		const thead = $('<thead>');
		const headerRow = $('<tr>');

		const actionHeader = $('<th>').text('Action');
		const regionHeader = $('<th>').text('Region').css('width', '40%'); // Make region column wider
		const branchHeader = $('<th>').text('Branch');

        const hasPendingChanges = officerChanges.length > 0;
		const statusHeader = $('<th>').text(hasPendingChanges ? 'Status' : '');
		headerRow.append(actionHeader, regionHeader, branchHeader, statusHeader);

		const idHeader = $('<th>').text('ID').css('display', 'none'); // Hidden ID column for debugging

		headerRow.append(actionHeader, regionHeader, branchHeader, statusHeader, idHeader);
		thead.append(headerRow);
		table.append(thead);

		// Add table body
		const tbody = $('<tbody>');

		// Sort assignments by region and branch
		const sortedAssignments = [...officerAssignments].sort((a, b) => {
			if (a.regionName !== b.regionName) {
				return a.regionName.localeCompare(b.regionName);
			}
			return a.branchName.localeCompare(b.branchName);
		});

		// Add each assignment to the table
		sortedAssignments.forEach(assignment => {
			// Ensure we have an ID, even if it's a temporary one
			const assignmentId = assignment.id || `temp-${Date.now()}-${Math.random()}`;

			// Create row with data attributes - make sure to include the id
			const row = $('<tr>').attr({
				'data-region': assignment.regionName,
				'data-branch': assignment.branchName,
				'data-officer': assignment.officerId,
				'data-id': assignmentId
			});

			// Action cell with remove icon
			const actionCell = $('<td>');
			const removeIcon = $('<a>')
				.html('❌') // Red X icon
				.attr('href', '#')
				.addClass('remove-icon')
				.attr('title', 'Remove this assignment')
				.on('click', function(e) {
					e.preventDefault();
					toggleOfficerAssignmentRemoval(row, assignment.officerId, assignment.regionName, assignment.branchName, assignmentId);
				});
			actionCell.append(removeIcon);

			const regionCell = $('<td>').text(assignment.regionName);
			const branchCell = $('<td>').text(assignment.branchName);
            const statusCell = $('<td>').addClass('status-cell'); // Initially empty
            row.append(actionCell, regionCell, branchCell, statusCell);

			const idCell = $('<td>').text(assignmentId).css('display', 'none'); // Hidden ID cell for debugging
			row.append(idCell);

			tbody.append(row);
		});

		table.append(tbody);
		list.append(table);
	}

	// Show the container
	container.show();

	// Update officer save changes link
	updateOfficerSaveChangesLink();
}

function toggleOfficerAssignmentRemoval(row, officerId, regionName, branchName, assignmentId) {
	// If row is a jQuery object, get native element for DOM operations if needed
	const rowElement = row[0];

	// Get cells with either jQuery or standard DOM methods
	const statusCell = row.find('.status-cell');
	const removeIcon = row.find('.remove-icon');

	// Create a change identifier
	const changeId = `${regionName}-${branchName}-${officerId}-remove`;

	// Check if this is already marked for removal
	const isMarkedForRemoval = removeIcon.hasClass('marked-for-removal');

	if (isMarkedForRemoval) {
		// User is undoing the removal
		removeIcon.removeClass('marked-for-removal');
		removeIcon.html('❌');
		statusCell.text('');
		statusCell.removeClass('remove-pending');

		// Remove from officer changes array
		const existingChangeIndex = officerChanges.findIndex(change => change.id === changeId);
		if (existingChangeIndex !== -1) {
			officerChanges.splice(existingChangeIndex, 1);
		}
	} else {
		// User is requesting removal
		removeIcon.addClass('marked-for-removal');
		removeIcon.html('↩️ <span style="font-size: 0.8em;">undo</span>'); // undo icon with text
		statusCell.text('Will be removed on save');
		statusCell.addClass('remove-pending');

		// Use the passed assignment ID or find it from the data attribute
		let idToDelete = assignmentId || row.data('id');

		// Additional console logging to debug assignment ID issues
		console.log(`Assignment removal requested: ${regionName}/${branchName}/${officerId}`);
		console.log(`Assignment ID from parameters: ${assignmentId}`);
		console.log(`Assignment ID from row data attribute: ${row.data('id')}`);

		// If still no ID, try to find it in the assignments array (fallback)
		if (!idToDelete) {
			const assignment = assignments.find(a => 
				a.regionName === regionName && 
				a.branchName === branchName && 
				a.officerId === officerId
			);

			idToDelete = assignment ? assignment.id : null;
			console.log(`Assignment ID from assignments array: ${idToDelete}`);
		}

		// Final check to ensure we have an ID
		if (!idToDelete) {
			console.error('❌ CRITICAL ERROR: Could not find assignment ID for deletion', {
				officerId, regionName, branchName
			});

			// Log all assignments to help debug
			console.log('All assignments:', assignments);

			showNotification('Error: Could not find assignment ID for deletion', 'error');
			return;
		}

		// Add to officer changes array if not already there and we have an ID
		const existingChange = officerChanges.find(change => change.id === changeId);
		if (!existingChange) {
			console.log(`Adding removal change with assignment ID: ${idToDelete}`);
			officerChanges.push({
				id: changeId,
				officerId: officerId,
				regionName: regionName,
				branchName: branchName,
				action: 'remove',
				originalState: true,
				assignmentId: idToDelete // Store the assignment ID for deletion
			});
		}
	}

	// Update the save changes link
	updateOfficerSaveChangesLink();

	// Log current state of changes
	console.log('Current officer changes:', officerChanges);
}

function handleOfficerRegionChange() {
	const regionSelect = $('#officerRegionSelect');
	const branchSelect = $('#officerBranchSelect');
	const confirmBtn = $('#confirmAddAssignment');
	const selectedRegion = regionSelect.val();

	// Clear existing branch options except the placeholder
	branchSelect.find('option:not(:first)').remove();

	// Reset branch selection
	branchSelect.prop('selectedIndex', 0);
	confirmBtn.prop('disabled', true);

	if (selectedRegion) {
		// Enable branch dropdown
		branchSelect.prop('disabled', false);

		// Filter branches for the selected region
		const filteredBranches = branches
			.filter(branch => branch.regionName === selectedRegion)
			.map(branch => branch.branchName);

		// Remove duplicates if there are any
		const uniqueBranches = [...new Set(filteredBranches)];

		// Sort branches alphabetically
		uniqueBranches.sort();

		// Add filtered branches to the dropdown
		uniqueBranches.forEach(branchName => {
			$('<option>', {
				value: branchName,
				text: branchName
			}).appendTo(branchSelect);
		});

		// Add event listener to branch select tag=2505041310
		branchSelect.off('change').on('change', function() {
			confirmBtn.prop('disabled', !branchSelect.val());
		});
	} else {
		// Disable branch dropdown if no region is selected
		branchSelect.prop('disabled', true);
	}
}

function addNewOfficerAssignment(officerId, regionName, branchName) {
    console.log("==== START addNewOfficerAssignment ====");

    // Find region and branch IDs
    const branchInfo = branches.find(b => 
        b.regionName === regionName && 
        b.branchName === branchName
    );

    const regionId = branchInfo ? branchInfo.regionId : null;
    const branchId = branchInfo ? branchInfo.branchId : null;

    if (!regionId || !branchId) {
        console.error(`Could not find IDs for region=${regionName}, branch=${branchName}`);
        showNotification('Error: Could not find region or branch IDs', 'error');
        return;
    }

    // Check if this assignment already exists
    const alreadyExists = assignments.some(a => 
        a.regionName === regionName && 
        a.branchName === branchName && 
        a.officerId === officerId
    );

    if (alreadyExists) {
        const officerName = loanOfficers.find(o => o.id === officerId)?.name || 'Officer';
        alert(`${officerName} is already assigned to ${regionName} - ${branchName}`);
        return;
    }

    // Check if this assignment is already in the changes array for removal
    const removalChangeIndex = officerChanges.findIndex(change => 
        change.action === 'remove' && 
        change.regionName === regionName && 
        change.branchName === branchName && 
        change.officerId === officerId
    );

    if (removalChangeIndex !== -1) {
        // This was marked for removal, so we're just undoing that
        officerChanges.splice(removalChangeIndex, 1);

        // Refresh the list to show it's no longer being removed
        handleOfficerLookup();
        return;
    }

    // Create a change identifier
    const changeId = `${regionName}-${branchName}-${officerId}-add`;

    // Add to officer changes array if not already there
    const existingAddChange = officerChanges.find(change => change.id === changeId);
    if (!existingAddChange) {
        officerChanges.push({
            id: changeId,
            officerId: officerId,
            regionName: regionName,
            branchName: branchName,
            action: 'add',
            originalState: false,
            regionId: regionId,
            branchId: branchId
        });
    }

    // Add to local assignments array for display purposes
    const newAssignment = {
        id: `temp-${Date.now()}`, // Generate a temporary ID for UI purposes
        regionName: regionName,
        branchName: branchName,
        officerId: officerId,
        regionId: regionId,
        branchId: branchId,
        isNew: true // Mark as new for UI purposes
    };

    assignments.push(newAssignment);

    // Refresh the display
    handleOfficerLookup();

    // Update the branches count in the other dropdown if it's the same region
    const mainRegionSelect = $('#regionSelect');
    if (mainRegionSelect.val() === regionName) {
        updateBranchOptionCount(regionName, branchName);
    }

    console.log("==== END addNewOfficerAssignment ====");
}

function updateOfficerSaveChangesLink() {
	const saveLink = $('#officerSaveChangesLink');

	// Update the link text based on changes count
	const changeCount = officerChanges.length;
	if (changeCount > 0) {
		saveLink.text(`Save ${changeCount} change${changeCount !== 1 ? 's' : ''}`);
		saveLink.show();
	} else {
		saveLink.hide();
	}
}

function saveOfficerChanges() {
	console.log(`Processing ${officerChanges.length} officer changes...`);

	// Verify CSRF token before proceeding
	if (!CSRF_TOKEN) {
		console.error('Cannot save changes: Missing CSRF token');
		showNotification('Error: Authentication token missing. Please refresh the page.', 'error');
		return;
	}

	// Validate changes before processing
	const invalidChanges = officerChanges.filter(change => {
		if (change.action === 'remove' && !change.assignmentId) {
			console.error(`Invalid change: Missing assignment ID for removal`, change);
			return true;
		}
		return false;
	});

	if (invalidChanges.length > 0) {
		console.error(`Found ${invalidChanges.length} invalid changes. Cannot proceed.`);
		showNotification('Error: Some changes are invalid and cannot be processed.', 'error');
		return;
	}

	// Track promises for all operations
	const savePromises = officerChanges.map(change => {
		if (change.action === 'add') {
			// Find branch information to get IDs
			const branchInfo = branches.find(b => 
				b.regionName === change.regionName && 
				b.branchName === change.branchName
			);

			if (branchInfo && branchInfo.regionId && branchInfo.branchId) {
				console.log(`Adding new assignment officer id=${change.officerId} to region=${change.regionName}(${branchInfo.regionId}) and branch=${change.branchName}(${branchInfo.branchId})`);
				return createAssignment(change.officerId, change.regionName, change.branchName, branchInfo.regionId, branchInfo.branchId);
			} else {
				console.error(`Could not find IDs for region=${change.regionName}, branch=${change.branchName}`);
				return Promise.reject(new Error('Region or Branch IDs not found'));
			}
		} else if (change.action === 'remove') {
			// Final validation before deletion
			if (!change.assignmentId) {
				console.error(`Cannot delete assignment: Missing ID for ${change.regionName}/${change.branchName}/${change.officerId}`);
				return Promise.reject(new Error('Missing assignment ID for deletion'));
			}

			console.log(`Remove assignment officer id=${change.officerId} from region=${change.regionName} and branch=${change.branchName}, assignment ID=${change.assignmentId}`);
			return deleteAssignment(change.assignmentId);
		}
	});

	// Show saving indicator
	const saveLink = $('#officerSaveChangesLink');
	const originalText = saveLink.text();
	saveLink.text('Saving...');
	saveLink.css('pointer-events', 'none');

	// Process all changes
	Promise.all(savePromises)
		.then(results => {
			console.log('All save operations completed successfully:', results);

			// Update local assignments array based on changes
			officerChanges.forEach(change => {
				if (change.action === 'remove') {
					// Remove this assignment
					const index = assignments.findIndex(a => 
						a.regionName === change.regionName && 
						a.branchName === change.branchName && 
						a.officerId === change.officerId
					);

					if (index !== -1) {
						console.log(`Removing assignment from local array: ${assignments[index].regionName}/${assignments[index].branchName}`);
						assignments.splice(index, 1);
					}
				}
				// For 'add' actions, we already added to the local array
			});

			// Clear changes after successful save
			officerChanges = [];

			// Refresh the view
			handleOfficerLookup();

            saveLink.text('Saved successfully!');
            saveLink.css('color', '#4CAF50'); // Green color for success
			saveLink.show(); // not sure if really necessary 

            // Timeout to hide the link after showing success
            setTimeout(() => {
				saveLink.hide();
                saveLink.css('color', '');
				saveLink.css('pointer-events', 'auto');
            }, 5000);		
		})
		.catch(error => {
			console.error('Error saving changes:', error);

            // Show error in the save link
            saveLink.text('Error: ' + (error.message || 'Unknown error'));
            saveLink.css('color', '#F44336'); // Red color for error

            // Set a timeout to restore the original text
            setTimeout(() => {
                saveLink.text(originalText);
                saveLink.css('color', '');
                saveLink.css('pointer-events', 'auto');
            }, 3000);
		});
}

// #endregion Loan Officer

function handleRegionChange() { // this is the region in the 2nd section, the one in the first section is named officerRegion
	console.log("ENTER: handleRegionChange");

    const regionSelect = document.getElementById('regionSelect');
    const branchSelect = document.getElementById('branchSelect'); // tag=2505041310
    const filterSelect = document.getElementById('filterSelect');
    const selectedRegion = regionSelect.value;

    saveIfConfirm();

    // Clear existing branch options except the placeholder
    while (branchSelect.options.length > 1) {
        branchSelect.remove(1);
    }

    // Reset branch selection
    branchSelect.selectedIndex = 0;

    // Disable filter dropdown and hide loan officers container
    filterSelect.disabled = true;
    document.getElementById('loanOfficersContainer').style.display = 'none';

    if (selectedRegion) {
        // Enable branch dropdown
        branchSelect.disabled = false;

        // Filter branches for the selected region
        const filteredBranches = branches
            .filter(branch => branch.regionName === selectedRegion)
            .map(branch => branch.branchName);

        // Remove duplicates if there are any
        const uniqueBranches = [...new Set(filteredBranches)];

        // Add filtered branches to the dropdown with count of assigned officers
        uniqueBranches.forEach(branchName => {
            // Count officers assigned to this region-branch combination
            const officerCount = assignments.filter(a => 
                a.regionName === selectedRegion && 
                a.branchName === branchName && 
                a.officerId
            ).length;

            const option = document.createElement('option');
            option.value = branchName;
            option.text = `${branchName} (${officerCount})`;
            branchSelect.add(option);
        });
    } else {
        // Disable branch dropdown if no region is selected
        branchSelect.disabled = true;
    }
}

function handleBranchChange() {
	console.log("ENTER: handleBranchChange");

    const regionSelect = document.getElementById('regionSelect');
    const branchSelect = document.getElementById('branchSelect');
    const filterSelect = document.getElementById('filterSelect');
    const selectedRegion = regionSelect.value;
    const selectedBranch = branchSelect.value;

    saveIfConfirm();

    if (selectedRegion && selectedBranch) {
        // Enable the filter dropdown
        filterSelect.disabled = false;

        // Show and populate loan officers list with the current filter
        displayLoanOfficers(selectedRegion, selectedBranch, currentFilter);
    } else {
        // Hide loan officers container and disable filter if either region or branch is not selected
        document.getElementById('loanOfficersContainer').style.display = 'none';
        filterSelect.disabled = true;
    }
}

function handleFilterChange() {
    const filterSelect = document.getElementById('filterSelect');
    const regionSelect = document.getElementById('regionSelect');
    const branchSelect = document.getElementById('branchSelect');
    const selectedRegion = regionSelect.value;
    const selectedBranch = branchSelect.value;

    // Update the current filter
    currentFilter = filterSelect.value;

    if (selectedRegion && selectedBranch) {
        displayLoanOfficers(selectedRegion, selectedBranch, currentFilter);
    }
}

function sortLoanOfficers(officers, sortColumn, sortDirection) {
    return [...officers].sort((a, b) => {
        let valueA, valueB;

        if (sortColumn === 'name') {
            valueA = a.name.toLowerCase();
            valueB = b.name.toLowerCase();
        } else if (sortColumn === 'assigned') {
            const selectedRegion = document.getElementById('regionSelect').value;
            const selectedBranch = document.getElementById('branchSelect').value;

            valueA = assignments.some(assignment => 
                assignment.regionName === selectedRegion && 
                assignment.branchName === selectedBranch && 
                assignment.officerId === a.id
            );

            valueB = assignments.some(assignment => 
                assignment.regionName === selectedRegion && 
                assignment.branchName === selectedBranch && 
                assignment.officerId === b.id
            );
        }

        if (valueA === valueB) return 0;

        if (sortDirection === 'asc') {
            return valueA < valueB ? -1 : 1;
        } else {
            return valueA > valueB ? -1 : 1;
        }
    });
}

function handleHeaderClick(column) {
    // If clicking the same column, toggle direction
    if (currentSortColumn === column) {
        currentSortDirection = currentSortDirection === 'asc' ? 'desc' : 'asc';
    } else {
        // If clicking a different column, set it as the current sort column with ascending direction
        currentSortColumn = column;
        currentSortDirection = 'asc';
    }

    // Refresh the display with the new sort settings
    const regionSelect = document.getElementById('regionSelect');
    const branchSelect = document.getElementById('branchSelect');
    displayLoanOfficers(regionSelect.value, branchSelect.value, currentFilter);
}

function displayLoanOfficers(regionName, branchName, filter) {
	console.log(`ENTER: displayLoanOfficers regionName=${regionName}; branchName=${branchName}; filter=${filter}`);

	const container = document.getElementById('loanOfficersContainer');
    const list = document.getElementById('loanOfficersList');

    // Clear existing list
    list.innerHTML = '';

    // Get assigned officer IDs for this region and branch
    const assignedOfficerIds = assignments
        .filter(a => a.regionName === regionName && a.branchName === branchName)
        .map(a => a.officerId);

    // Create a table for loan officers
    const table = document.createElement('table');
    table.className = 'loan-officers-table';

    // Add table header
    const thead = document.createElement('thead');
    const headerRow = document.createElement('tr');

    const checkboxHeader = document.createElement('th');
    checkboxHeader.textContent = 'Assigned';
    checkboxHeader.className = 'sortable-header';
    checkboxHeader.dataset.column = 'assigned';
    if (currentSortColumn === 'assigned') {
        checkboxHeader.className += currentSortDirection === 'asc' ? ' sort-asc' : ' sort-desc';
    }
    checkboxHeader.addEventListener('click', () => handleHeaderClick('assigned'));

    const nameHeader = document.createElement('th');
    nameHeader.textContent = 'Loan Officer';
    nameHeader.className = 'sortable-header';
    nameHeader.dataset.column = 'name';
    if (currentSortColumn === 'name') {
        nameHeader.className += currentSortDirection === 'asc' ? ' sort-asc' : ' sort-desc';
    }
    nameHeader.addEventListener('click', () => handleHeaderClick('name'));

    headerRow.appendChild(checkboxHeader);
    headerRow.appendChild(nameHeader);
    thead.appendChild(headerRow);
    table.appendChild(thead);

    // Add table body
    const tbody = document.createElement('tbody');

    // Filter loan officers based on the selected filter
    let filteredOfficers = loanOfficers;

    if (filter === 'assigned') {
        filteredOfficers = loanOfficers.filter(officer => 
            assignedOfficerIds.includes(officer.id)
        );
    } else if (filter === 'unassigned') {
        filteredOfficers = loanOfficers.filter(officer => 
            !assignedOfficerIds.includes(officer.id)
        );
    }

    // Sort loan officers based on current sort settings
    const sortedOfficers = sortLoanOfficers(filteredOfficers, currentSortColumn, currentSortDirection);

    // Add each loan officer to the table
    sortedOfficers.forEach(officer => {
        const row = document.createElement('tr');

        // Create checkbox cell
        const checkboxCell = document.createElement('td');
        const checkbox = document.createElement('input');
        checkbox.type = 'checkbox';
        checkbox.id = `officer-${officer.id}`;
        checkbox.checked = assignedOfficerIds.includes(officer.id);
        checkbox.addEventListener('change', function() {
            toggleOfficerAssignment(officer.id, regionName, branchName, this.checked);
        });
        checkboxCell.appendChild(checkbox);

        // Create name cell
        const nameCell = document.createElement('td');
        nameCell.textContent = officer.name;

        // Add cells to row
        row.appendChild(checkboxCell);
        row.appendChild(nameCell);

        // Add row to table body
        tbody.appendChild(row);
    });

    table.appendChild(tbody);
    list.appendChild(table);

    // Create the heading and save link area immediately (before adding any officers)
    if (!document.getElementById('saveChangesContainer')) {
        const headingContainer = document.querySelector('#loanOfficersContainer h3');

        // Create a container for the save link that always occupies space
        const linkContainer = document.createElement('span');
        linkContainer.id = 'saveChangesContainer';
        linkContainer.style.marginLeft = '15px';
        linkContainer.style.display = 'inline-block';
        linkContainer.style.minWidth = '120px'; // Reserve space for the link text

        // Create the actual save link (initially hidden)
        const saveLink = document.createElement('a');
        saveLink.id = 'saveChangesLink';
        saveLink.href = '#';
        saveLink.className = 'save-changes-link';
        saveLink.addEventListener('click', function(e) {
            e.preventDefault();
            saveChanges();
        });

        // Add the link to the container
        linkContainer.appendChild(saveLink);

        // Add the container after the heading
        headingContainer.appendChild(linkContainer);
    }

    // Show the container
    container.style.display = 'block';
}

function toggleOfficerAssignment(officerId, regionName, branchName, isAssigned) {
    console.log(`${isAssigned ? 'Assigning' : 'Removing'} officer ${officerId} ${isAssigned ? 'to' : 'from'} ${regionName}/${branchName}`);

	// Find region and branch IDs
	const branchInfo = branches.find(b => 
		b.regionName === regionName && 
		b.branchName === branchName
	);

	const regionId = branchInfo ? branchInfo.regionId : null;
	const branchId = branchInfo ? branchInfo.branchId : null;

	if (!regionId || !branchId) {
		console.error(`Could not find IDs for region=${regionName}, branch=${branchName}`);
		showNotification('Error: Could not find region or branch IDs', 'error');
		return;
	}

    // Create a change identifier
    const changeId = `${regionName}-${branchName}-${officerId}`;

    // Check if this change already exists in our changes array
    const existingChangeIndex = changes.findIndex(change => 
        change.id === changeId
    );

    if (existingChangeIndex !== -1) {
        // If the change exists and is returning to original state, remove it
        const existingChange = changes[existingChangeIndex];
        if (existingChange.isAssigned !== isAssigned) {
            // This is reverting to original state, so remove the change
            changes.splice(existingChangeIndex, 1);
        }
    } else {
        // This is a new change, add it to our changes array
        // Find the existing assignment if any
        const existingAssignment = assignments.find(a => 
            a.regionName === regionName && 
            a.branchName === branchName && 
            a.officerId === officerId
        );

        const originalState = existingAssignment !== undefined;

        // Only add if the state is actually changing
        if (originalState !== isAssigned) {
            const change = {
                id: changeId,
                officerId: officerId,
                regionName: regionName,
                branchName: branchName,
                isAssigned: isAssigned,
                originalState: originalState
            };

            // If we're removing an existing assignment, store its ID
            if (!isAssigned && existingAssignment && existingAssignment.id) {
                change.assignmentId = existingAssignment.id;
            }

            changes.push(change);
        }
    }

    // Update the local data structure
    if (isAssigned) {
        // Add assignment if it doesn't exist
        const exists = assignments.some(a => 
            a.regionName === regionName && 
            a.branchName === branchName && 
            a.officerId === officerId
        );

        if (!exists) {
            assignments.push({
                regionName: regionName,
                branchName: branchName,
                officerId: officerId,
				regionId: regionId,
				branchId: branchId
            });
        }
    } else {
        // Remove assignment if it exists
        const index = assignments.findIndex(a => 
            a.regionName === regionName && 
            a.branchName === branchName && 
            a.officerId === officerId
        );

        if (index !== -1) {
            assignments.splice(index, 1);
        }
    }

    // Update the branch dropdown option to show the new count
    updateBranchOptionCount(regionName, branchName);

    // Refresh the loan officers list to reflect the changes
    displayLoanOfficers(regionName, branchName, currentFilter);

    // Make sure to update the save changes link
    updateSaveChangesLink();

    console.log("Current changes:", changes);
}

function updateSaveChangesLink() {
    const saveLink = document.getElementById('saveChangesLink');

    // Update the link text based on changes count
    const changeCount = changes.length;
    if (changeCount > 0) {
        saveLink.textContent = `Save ${changeCount} change${changeCount !== 1 ? 's' : ''}`;
        saveLink.style.display = 'inline';
    } else {
        saveLink.style.display = 'none';
    }
}

function saveIfConfirm() { // if no changes, does nothing. But, if changes found, calls confirm
    if (changes.length > 0) {
        if (confirm("You have unsaved changes. Choose 'OK' to save them now. Choose 'Cancel' to discard your changes")) {
            saveChanges();
        } else {
            changes = [];
            updateSaveChangesLink();
        }
    }

    // Also check for officer changes
    if (officerChanges.length > 0) {
        if (confirm("You have unsaved officer assignment changes. Choose 'OK' to save them now. Choose 'Cancel' to discard your changes")) {
            saveOfficerChanges();
        } else {
            officerChanges = [];
            updateOfficerSaveChangesLink();
            handleOfficerLookup(); // Refresh the view
        }
    }
}

function saveChanges() {
    console.log(`Processing ${changes.length} changes...`);

    // Track promises for all operations
	const savePromises = changes.map(change => {
		if (change.isAssigned) {
			// Find assignment with IDs in the assignments array
			const assignment = assignments.find(a => 
				a.regionName === change.regionName && 
				a.branchName === change.branchName && 
				a.officerId === change.officerId
			);

			if (assignment && assignment.regionId && assignment.branchId) {
				console.log(`Adding new assignment officer id=${change.officerId} to region=${change.regionName}(${assignment.regionId}) and branch=${change.branchName}(${assignment.branchId})`);
				return createAssignment(change.officerId, change.regionName, change.branchName, assignment.regionId, assignment.branchId);
			} else {
				// Find IDs from branches array if not in assignments
				const branchInfo = branches.find(b => 
					b.regionName === change.regionName && 
					b.branchName === change.branchName
				);

				if (branchInfo && branchInfo.regionId && branchInfo.branchId) {
					console.log(`Adding new assignment officer id=${change.officerId} to region=${change.regionName}(${branchInfo.regionId}) and branch=${change.branchName}(${branchInfo.branchId})`);
					return createAssignment(change.officerId, change.regionName, change.branchName, branchInfo.regionId, branchInfo.branchId);
				} else {
					console.error(`Could not find IDs for region=${change.regionName}, branch=${change.branchName}`);
					return Promise.reject(new Error('Region or Branch IDs not found'));
				}
			}
		} else {
			// Delete logic remains the same
			const assignment = assignments.find(a => 
				a.regionName === change.regionName && 
				a.branchName === change.branchName && 
				a.officerId === change.officerId
			);

			if (assignment && assignment.id) {
				console.log(`Remove assignment officer id=${change.officerId} from region=${change.regionName} and branch=${change.branchName}, assignment ID=${assignment.id}`);
				return deleteAssignment(assignment.id);
			} else {
				console.error(`Could not find assignment ID for officer=${change.officerId}, region=${change.regionName}, branch=${change.branchName}`);
				return Promise.reject(new Error('Assignment ID not found'));
			}
		}
	});

    // Show saving indicator
    const saveLink = document.getElementById('saveChangesLink');
    const originalText = saveLink.textContent;
    saveLink.textContent = 'Saving...';
    saveLink.style.pointerEvents = 'none';

    // Process all changes
    Promise.all(savePromises)
        .then(() => {
            // Clear changes after successful save
            changes = [];

            // Show error in the save link
            saveLink.text('Error: ' + (error.message || 'Unknown error'));
            saveLink.css('color', '#F44336'); // Red color for error

            // Set a timeout to restore the original text
            setTimeout(() => {
                saveLink.text(originalText);
                saveLink.css('color', '');
                saveLink.css('pointer-events', 'auto');
            }, 3000);

			saveLink.style.pointerEvents = 'auto';
        })
        .catch(error => {
            console.error('Error saving changes:', error);

            // Show error in the save link
            saveLink.textContent = 'Error: ' + (error.message || 'Unknown error');
            saveLink.style.color = '#F44336'; // Red color for error

            // Set a timeout to restore the original text
            setTimeout(() => {
                saveLink.textContent = originalText;
                saveLink.style.color = '';
                saveLink.style.pointerEvents = 'auto';
            }, 3000);
	});
}

function createAssignment(officerId, regionName, branchName, regionId, branchId) { // previous versions of this function required names, but they are no longer used other than for console logging
	if (!officerId || !regionName || !branchName || !regionId || !branchId) {
		console.error('Cannot create assignment: Missing required parameters', { officerId, regionName, branchName, regionId, branchId });
		return Promise.reject(new Error('Missing required parameters'));
	}

	console.log(`createAssignment::: officerId=${officerId}; regionName=${regionName}; branchName=${branchName}; regionId=${regionId}; branchId=${branchId}`);

	const url = '/_api/lv_lvcompregionbranchloanofficers';

	console.log('Create assignment: url=' + url + '; ' + officerId + "; region: " + regionName + "(" + regionId + "); branch: " + branchName + "(" + branchId + ")");

	// Updated postBody to include both officer and branch lookups with their IDs
	const postBody = JSON.stringify({
		"lv_LoanOfficer@odata.bind": `/lv_lvcomploanofficers(${officerId})`,
		"lv_Region@odata.bind": `/accounts(${regionId})`,
		"lv_Branch@odata.bind": `/lv_lvcompbranchs(${branchId})`
	});

	console.log("POST body: " + postBody);

	return $.ajax({
		url: url,
		type: 'POST',
		headers: {
			'Content-Type': 'application/json',
			'__RequestVerificationToken': CSRF_TOKEN
		},
		data: postBody
	}).catch(error => {
		console.error('Failed to create assignment:', error.status, error.statusText, error.responseText || 'No error details');
		throw new Error(`Failed to create assignment: ${error.status} ${error.statusText}`);
	});
}

function deleteAssignment(rbloId) {
	if (!rbloId) {
		console.error('Cannot delete assignment: Missing ID');
		return Promise.reject(new Error('Missing assignment ID'));
	}

	const url = `/_api/lv_lvcompregionbranchloanofficers(${rbloId})`;

	console.log('DELETE assignment: url=' + url);

	return $.ajax({
		url: url,
		type: 'DELETE',
		headers: {
			'Content-Type': 'application/json',
			'__RequestVerificationToken': CSRF_TOKEN
		}
	}).catch(error => {
		console.error('Failed to delete assignment:', error.status, error.statusText, error.responseText || 'No error details');
		throw new Error(`Failed to delete assignment: ${error.status} ${error.statusText}`);
	});
}

function showNotification(message, type) {
	// Create notification element if it doesn't exist
	let notification = $('#notification');
	if (notification.length === 0) {
		notification = $('<div>', {
			id: 'notification',
			css: {
				position: 'fixed',
				bottom: '20px',
				right: '20px',
				padding: '10px 20px',
				borderRadius: '4px',
				color: 'white',
				zIndex: '1000',
				boxShadow: '0 2px 10px rgba(0,0,0,0.2)'
			}
		}).appendTo('body');
	}

	// Set style based on type
	notification.css('backgroundColor', type === 'success' ? '#4CAF50' : '#F44336');
	notification.text(message);

	// Show and then hide after delay
	notification.show();
	setTimeout(() => {
		notification.hide();
	}, 3000);
}

function updateBranchOptionCount(regionName, branchName) {
	const branchSelect = $('#branchSelect');

	// Find the option for this branch
	branchSelect.find('option').each(function() {
		if ($(this).val() === branchName) {
			// Count officers assigned to this region-branch
			const officerCount = assignments.filter(a => 
				a.regionName === regionName && 
				a.branchName === branchName && 
				a.officerId
			).length;

			// Update the option text with the new count
			$(this).text(`${branchName} (${officerCount})`);
			return false; // Break the loop
		}
	});
}

document.addEventListener('LVGlobalDOCReady', async function() {
	// Setup save changes links
	$('#saveChangesLink').on('click', function(e) {
		e.preventDefault();
		saveChanges();
	});

	$('#officerSaveChangesLink').on('click', function(e) {
		e.preventDefault();
		saveOfficerChanges();
	});

	// Bind the officer lookup change handler
	$('#officerLookup').on('change', handleOfficerLookup);

	$('#officerRegionSelect').on('change', handleOfficerRegionChange);

	// Setup officer assignment handlers
	const addLink = $('#addAssignmentLink');
	const addControls = $('#addAssignmentControls');
	const confirmBtn = $('#confirmAddAssignment');

	addLink.on('click', function(e) {
		e.preventDefault();
		addLink.hide();
		addControls.css('display', 'flex');
	});

	confirmBtn.on('click', function() {
		const officerId = $('#officerLookup').val();
		const regionName = $('#officerRegionSelect').val();
		const branchName = $('#officerBranchSelect').val();

		if (officerId && regionName && branchName) {
			addNewOfficerAssignment(officerId, regionName, branchName);

			// Reset the add controls
			//addControls.hide();
			//addLink.show();
			//$('#officerRegionSelect').prop('selectedIndex', 0);
			$('#officerBranchSelect').prop('selectedIndex', 0);
			//$('#officerBranchSelect').prop('disabled', true);
			confirmBtn.prop('disabled', true);
		}
	});

	setTimeout(function() {

		// Trigger the change handler to load the officer's assignments
		// Officer may have been set from local storage
		handleOfficerLookup();
		handleOfficerRegionChange();
		// Now the branch down should have valid values
		restoreElementValue('officerBranchSelect', true);
		// Now have to do the manual equivalent of what happens when officer branch change. 
		// see tag=2505041310
		//confirmBtn.prop('disabled', !branchSelect.val());
		confirmBtn.prop('disabled', !$('#officerBranchSelect').val())

		// In the 2nd section, we have a cascade Region to Branch. Region
		// may have gotten restored from local storage, but Branch population
		// and set may have failed. Let's force it after the delay
		handleRegionChange(); // this is the region in the 2nd section, not the officer section
		// Now, Branch dropdown will be properly populated
		restoreElementValue('branchSelect', true);	
		handleBranchChange();

	}, 2000);

});

</script>

